class Solution:
    def minimumPrefixLength(self, nums):
        n = len(nums)
        for cut in range(n):
            suffix = nums[cut:]
            if all(suffix[i] < suffix[i + 1] for i in range(len(suffix) - 1)):
                return cut
        return n - 1

